def A394824row(n) -> list[int]:
    row = [0] * (n + 1); row[n] = 1
    for k in range(n, 0, -1):
        row[k - 1] = (2 * k - 1) * row[k] + k * (n - k) * (row[k + 1] if k + 1 <= n else 0)
    return row
